          "comment": "控制器",
          "content": "@@generate_before\n<%_\nconst affection = getvar('stat_data.穗秋生.好感度[0]') || 5;\nconst fear = getvar('stat_data.穗秋生.害怕值[0]') || 95;\nconst dependence = getvar('stat_data.穗秋生.依赖值[0]') || 100;\n_%>\n\n<%# 基础人设永远激活 %>\n<%- await getwi(null, '穗秋生_基础角色信息') %>\n\n<%# 根据好感度判断阶段 %>\n<% if (affection === 100 && fear === 0 && dependence === 100) { %>\n  <%- await getwi(null, '性格锚定_阶段06') %>\n  <%- await getwi(null, '语料_阶段06') %>\n  <%- await getwi(null, '细节特化_阶段06') %>\n<% } else if (affection >= 81) { %>\n  <%- await getwi(null, '性格锚定_阶段05') %>\n  <%- await getwi(null, '语料_阶段05') %>\n  <%- await getwi(null, '细节特化_阶段05') %>\n<% } else if (affection >= 61) { %>\n  <%- await getwi(null, '性格锚定_阶段04') %>\n  <%- await getwi(null, '语料_阶段04') %>\n  <%- await getwi(null, '细节特化_阶段04') %>\n<% } else if (affection >= 41) { %>\n  <%- await getwi(null, '性格锚定_阶段03') %>\n  <%- await getwi(null, '语料_阶段03') %>\n  <%- await getwi(null, '细节特化_阶段03') %>\n<% } else if (affection >= 21) { %>\n  <%- await getwi(null, '性格锚定_阶段02') %>\n  <%- await getwi(null, '语料_阶段02') %>\n  <%- await getwi(null, '细节特化_阶段02') %>\n<% } else { %>\n  <%- await getwi(null, '性格锚定_基础阶段') %>\n  <%- await getwi(null, '语料_基础阶段') %>\n  <%- await getwi(null, '细节特化_基础阶段') %>\n<% } %>\n",
